def parse_cookie(
    environ_or_str: t.Union[str, "WSGIEnvironment"],
    charset: str = "utf-8",
    errors: str = "replace",
    cls: t.Optional[t.Type["ds.MultiDict"]] = None,
) -> "ds.MultiDict[str, str]":
    """Parse a cookie from a string or WSGI environ.

    .. versionchanged:: 2.0
        The ``environ_or_str`` parameter can be a string or WSGI
        environ dict.
    .. versionchanged:: 0.5
       added the ``cls`` parameter.

    :param environ_or_str: A string with the cookie data or a WSGI
        environment dict.
    :param charset: The charset for the cookie values.
    :param errors: The error behavior for the charset decoding.
    :param cls: A dict-like class to store the parsed cookies in.
        Defaults to :class:`~werkzeug.datastructures.MultiDict`.
    """
    if isinstance(environ_or_str, str):
        cookie = environ_or_str
    else:
        cookie = environ_or_str.get("HTTP_COOKIE")

    if cookie is None:
        if cls is None:
            cls = ds.MultiDict

        return cls()

    return sansio_http.parse_cookie(
        cookie, charset=charset, errors=errors, cls=cls  # type: ignore
    )
